// All string forms
const a: string = 'single quotes';
const b: string = "double quotes";
const c: string = `template literal`;
const d: string = `Hello, ${a}`;  // interpolation OK

// String methods are fully typed
const upper = a.toUpperCase();       // string
const sliced = b.slice(0, 6);        // string
const parts = d.split(', ');         // string[]

// Angular component property
@Component({ selector: 'app-greeting', template: '<h1>{{ title }}</h1>' })
class GreetingComponent {
  title: string = 'Welcome';
  subtitle = 'To my app';  // inferred: string
}

// Template literal in a union
type HttpMethod = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';
type ApiPath   = `/api/${string}`;

const age: number = 30;
const price: number = 9.99;
const hex: number = 0xff;        // 255
const binary: number = 0b1010;   // 10
const octal: number = 0o17;      // 15

// Special values
const noValue: number = NaN;
const huge: number = Infinity;

// Arithmetic
const total = price * 1.1;       // number (10.989)

// Type guard for NaN
function safeLog(n: number): void {
  if (isNaN(n)) {
    console.warn('Not a number');
    return;
  }
  console.log(n.toFixed(2));
}

// Angular: form value parsing
const rawInput = '42.5';
const parsed: number = parseFloat(rawInput);
// Note: parseFloat returns NaN for invalid input — always guard

let isActive: boolean = true;
let isLoading: boolean = false;

// TypeScript enforces: only true or false
// isActive = 1;   // TS2322 — number is not assignable to boolean
// isActive = '';  // TS2322 — string is not assignable to boolean

// Computed booleans retain the type
const hasPremium: boolean = user.plan === 'premium';
const isEmpty: boolean = items.length === 0;

// Angular: toggling
@Component({ selector: 'app-toggle', template: '<button [disabled]="!canSubmit">Submit</button>' })
class ToggleComponent {
  canSubmit: boolean = false;

  enableSubmit(): void {
    this.canSubmit = true;
  }
}

// Literal boolean types (useful in discriminated unions)
type LoadingState =
  | { loading: true }
  | { loading: false; data: string[] };

const large: bigint = 9007199254740993n;   // safe — beyond MAX_SAFE_INTEGER
const sum: bigint = large + 1n;              // must use n literals in bigint arithmetic

// Mixed arithmetic is an error
// const mixed = large + 1;  // TS2365 — bigint and number are not compatible

// Converting
const n: number = Number(large);    // loses precision if too large
const b: bigint = BigInt(Number.MAX_SAFE_INTEGER);

// Comparison with number is allowed
console.log(large > 9007199254740991);  // true — mixed comparison OK

// Angular use-case: financial calculations, cryptographic IDs
type TransactionId = bigint;

// symbol — any symbol value
const id1: symbol = Symbol('id');
const id2: symbol = Symbol('id');
console.log(id1 === id2); // false — always different

// unique symbol — tied to this exact declaration
const KEY: unique symbol = Symbol('KEY');
type KEY = typeof KEY;  // refer to the type by the same name

// Symbols as object keys (avoids name collisions in mixins)
const LOGGER = Symbol('logger');

interface WithLogger {
  [LOGGER]: { log(msg: string): void };
}

// Angular: rarely used directly, but the DI token system uses symbols internally
// InjectionToken wraps a description string — symbol semantics under the hood
const CONFIG_TOKEN = new InjectionToken<AppConfig>('AppConfig');

// strictNullChecks separates these
let a: string = 'hello';
// a = null;      // TS2322 — must be string | null
// a = undefined; // TS2322 — must be string | undefined

// Explicit nullable types
let name: string | null = null;        // not yet loaded
let optVal: string | undefined;        // optional property

// typeof narrows at runtime
function printName(n: string | null): void {
  if (n === null) {
    console.log('(no name)');
  } else {
    console.log(n.toUpperCase()); // n: string here
  }
}

// Angular: component state before data arrives
export class UserComponent {
  user: User | null = null;     // null until HTTP resolves
  error: string | null = null;

  ngOnInit(): void {
    this.service.getUser().subscribe({
      next: u => (this.user = u),
      error: e => (this.error = e.message),
    });
  }
}

function processInput(value: unknown): string {
  // Cannot use value directly
  // value.toUpperCase(); // TS2571

  if (typeof value === 'string') {
    return value.toUpperCase(); // string here
  }
  if (typeof value === 'number') {
    return value.toFixed(2);    // number here
  }
  if (Array.isArray(value)) {
    return value.join(', ');    // any[] here
  }
  return String(value);
}

// Angular: HTTP error handling
catchError((err: unknown) => {
  if (err instanceof HttpErrorResponse) {
    return throwError(() => new Error(`HTTP ${err.status}: ${err.message}`));
  }
  if (err instanceof Error) {
    return throwError(() => err);
  }
  return throwError(() => new Error('Unknown error'));
})

// JSON.parse returns any — cast to unknown for safety
function safeParseJSON(raw: string): unknown {
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

let legacy: any = fetchLegacyData();
legacy.foo.bar.baz;  // no error — but might throw at runtime
legacy = 42;         // reassigning any to any — fine
legacy = 'hello';    // also fine

// any spreads — assigning any to a typed variable bypasses checks
let name: string = legacy;  // no TS error — any is assignable to everything
// name.toUpperCase();       // may throw if legacy was not actually a string

// Prefer unknown for external data
function parseResponse(raw: string): User {
  const parsed: unknown = JSON.parse(raw);
  // Must narrow or assert before use
  return parsed as User; // type assertion — caller's responsibility
}

// When any is OK: quick prototype, legacy migration
const temp: any = require('some-untyped-lib');

// Standard void return
function logMessage(msg: string): void {
  console.log(msg);
  // no return statement needed
}

// void vs undefined
function explicit(): undefined {
  return undefined; // must return undefined explicitly
}

function voidFn(): void {
  return;            // OK
  // return 42;     // TS2322 — not assignable to void
}

// Angular lifecycle hooks are void
@Component({ selector: 'app-ex', template: '' })
class ExComponent implements OnInit, OnDestroy {
  ngOnInit(): void {
    this.load();
  }
  ngOnDestroy(): void {
    this.cleanup();
  }
  private load(): void { /* ... */ }
  private cleanup(): void { /* ... */ }
}

// Callback type with void return (caller ignores return value)
type EventHandler = (event: Event) => void;
const handler: EventHandler = (e) => {
  e.preventDefault();
  // no return value required
};

// Function that always throws — never returns
function fail(message: string): never {
  throw new Error(message);
}

// Exhaustive check — TypeScript flags unhandled cases
type Shape = 'circle' | 'square' | 'triangle';

function area(shape: Shape): number {
  switch (shape) {
    case 'circle':   return Math.PI * 1;
    case 'square':   return 1;
    case 'triangle': return 0.5;
    default:
      // If all cases are handled, shape is narrowed to never here
      const _exhaustive: never = shape;
      return _exhaustive; // TypeScript allows: never is assignable to anything
  }
}

// Adding 'hexagon' to Shape without updating area() causes a TS error
// on the _exhaustive line — catches missing cases at compile time

// Angular: guard functions that throw
function assertDefined<T>(value: T | null | undefined, name: string): T {
  if (value == null) {
    fail(`Expected ${name} to be defined`);  // fail returns never → this branch never continues
  }
  return value; // TypeScript knows value is T here
}

let obj: object = { name: 'Alice' };  // OK
obj = [1, 2, 3];                        // OK — arrays are objects
obj = () => {};                         // OK — functions are objects
// obj = 42;     // TS2322 — number is a primitive
// obj = 'hi';   // TS2322 — string is a primitive

// object doesn't let you access properties
// obj.name;  // TS2339 — Property 'name' does not exist on type 'object'

// Use specific types instead
const user: { name: string; age: number } = { name: 'Alice', age: 30 };
const list: string[] = ['a', 'b'];
const fn: (x: number) => number = x => x * 2;

// Record<string, unknown> is more useful than object for dynamic keys
function merge(base: Record<string, unknown>, ...overrides: Record<string, unknown>[]): Record<string, unknown> {
  return Object.assign({}, base, ...overrides);
}

function describe(value: string | number | boolean | null | undefined): string {
  if (typeof value === 'string')  return `string: "${value}"`;
  if (typeof value === 'number')  return isNaN(value) ? 'NaN' : `number: ${value}`;
  if (typeof value === 'boolean') return `boolean: ${value}`;
  if (value === null)             return 'null';
  return 'undefined';
}

// Note: typeof null === 'object' in JavaScript — always check === null separately
function processOrDefault(input: unknown): string {
  if (input === null || input === undefined) {
    return 'missing';
  }
  if (typeof input === 'string') {
    return input.trim();
  }
  if (typeof input === 'number') {
    return input.toFixed(2);
  }
  return JSON.stringify(input);
}

function logUser(user: User | null | undefined): void {
  if (user == null) {
    // == null catches BOTH null and undefined
    console.log('No user');
    return;
  }
  // user is User here
  console.log(user.name);
}

// Strict equality narrows to exactly one value
function handleStatus(status: 'active' | 'inactive' | 'pending'): void {
  if (status === 'active') {
    // status: 'active'
    console.log('User is active');
  } else {
    // status: 'inactive' | 'pending'
    console.log('User is not active');
  }
}

class HttpError extends Error {
  constructor(public status: number, message: string) { super(message); }
}

class NetworkError extends Error {
  constructor(message: string) { super(message); }
}

function handleError(err: unknown): string {
  if (err instanceof HttpError) {
    return `HTTP ${err.status}: ${err.message}`;
  }
  if (err instanceof NetworkError) {
    return `Network: ${err.message}`;
  }
  if (err instanceof Error) {
    return err.message;
  }
  return 'Unknown error';
}

// Primitive inference from literals
const s = 'hello';         // type: string
const n = 42;              // type: number
const b = true;            // type: boolean
const bi = 100n;           // type: bigint
const sym = Symbol('id');  // type: symbol

// const narrows to literal type
const MODE = 'dark';       // type: 'dark' (not string)
const MAX  = 100;          // type: 100 (not number)

// let widens to base type
let mode = 'dark';         // type: string (can be reassigned to any string)
let count = 0;             // type: number

// null and undefined
const n1 = null;           // type: null
const u1 = undefined;      // type: undefined
let  nu = null;            // type: null (under strict)

// Array inference
const items = ['a', 'b'];  // type: string[]
const mixed = [1, 'two'];  // type: (string | number)[]
const empty = [];           // type: never[] — annotate explicitly

import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

interface Product {
  id: number;
  name: string;
  price: number;
  available: boolean;
  description: string | null;
}

interface ApiResponse<T> {
  data: T;
  total: number;
  page: number;
}

@Injectable({ providedIn: 'root' })
class ProductService {
  private readonly http = inject(HttpClient);

  // number in URL, Product[] in response
  getProducts(page: number = 1): Observable<ApiResponse<Product[]>> {
    return this.http.get<ApiResponse<Product[]>>(`/api/products?page=${page}`);
  }

  // string ID, nullable description
  getProduct(id: number): Observable<Product> {
    return this.http.get<Product>(`/api/products/${id}`);
  }

  // boolean flag
  toggleAvailability(id: number, available: boolean): Observable<Product> {
    return this.http.patch<Product>(`/api/products/${id}`, { available });
  }

  // void return — delete returns no body
  delete(id: number): Observable<void> {
    return this.http.delete<void>(`/api/products/${id}`);
  }
}

// With useUnknownInCatchVariables: true (strict)
try {
  JSON.parse('{bad json}');
} catch (e) {
  // e is unknown — must narrow
  if (e instanceof SyntaxError) {
    console.error('Parse failed:', e.message);
  }
}

// Without strictNullChecks (avoid this):
function greet(name: string): void {
  console.log(name.toUpperCase()); // might crash if null passed
}

// With strictNullChecks (correct):
function greetSafe(name: string | null): void {
  if (name === null) { console.log('Hello, Guest'); return; }
  console.log(name.toUpperCase()); // safe
}
